## 4. Disposable Lifecycle System (lifecycle.ts)

### IDisposable Interface
```typescript
export interface IDisposable {
	dispose(): void;
}
```

**Universal cleanup contract for all managed resources.**

### DisposableStore (lifecycle.ts:416-519)
```typescript
export class DisposableStore implements IDisposable {
	private readonly _toDispose = new Set<IDisposable>();
	private _isDisposed = false;

	dispose(): void {
		if (this._isDisposed) return;
		markAsDisposed(this);
		this._isDisposed = true;
		this.clear();
	}

	add<T extends IDisposable>(o: T): T {
		if (!o || o === Disposable.None) return o;
		setParentOfDisposable(o, this);
		if (this._isDisposed) {
			console.warn('Adding to disposed store...');
		} else {
			this._toDispose.add(o);
		}
		return o;
	}

	delete<T extends IDisposable>(o: T): void {
		this._toDispose.delete(o);
		o.dispose();
	}

	clear(): void {
		dispose(this._toDispose);
		this._toDispose.clear();
	}
}
```

**Key behaviors:**
- Safe registration of multiple disposables
- Handles re-entrance (adding to already-disposed store)
- Tracks parent-child relationships for leak detection
- Centralized cleanup

### MutableDisposable (lifecycle.ts:565-630)
```typescript
export class MutableDisposable<T extends IDisposable> implements IDisposable {
	private _value?: T;
	private _isDisposed = false;

	get value(): T | undefined {
		return this._isDisposed ? undefined : this._value;
	}

	set value(value: T | undefined) {
		if (this._isDisposed || value === this._value) return;

		this._value?.dispose();  // Clean up old value
		if (value) {
			setParentOfDisposable(value, this);
		}
		this._value = value;  // Store new value
	}

	dispose(): void {
		this._isDisposed = true;
		markAsDisposed(this);
		this._value?.dispose();
		this._value = undefined;
	}
}
```

**Pattern:** Manages lifecycle of a single mutable resource.

### Disposable (abstract base class) (lifecycle.ts:526-557)
```typescript
export abstract class Disposable implements IDisposable {
	static readonly None = Object.freeze<IDisposable>({ dispose() { } });
	protected readonly _store = new DisposableStore();

	constructor() {
		trackDisposable(this);
		setParentOfDisposable(this._store, this);
	}

	dispose(): void {
		markAsDisposed(this);
		this._store.dispose();
	}

	protected _register<T extends IDisposable>(o: T): T {
		return this._store.add(o);
	}
}
