### Event Composition Functions

#### `Event.debounce` (event.ts:260-322)
```typescript
export function debounce<I, O>(
	event: Event<I>,
	merge: (last: O | undefined, event: I) => O,
	delay: number | typeof MicrotaskDelay = 100,
	leading = false,
	flushOnListenerRemove = false,
	leakWarningThreshold?: number,
	disposable?: DisposableStore
): Event<O> {
	let subscription: IDisposable;
	let output: O | undefined = undefined;
	let handle: Timeout | undefined | null = undefined;
	let numDebouncedCalls = 0;

	const options: EmitterOptions = {
		leakWarningThreshold,
		onWillAddFirstListener() {
			subscription = event(cur => {
				numDebouncedCalls++;
				output = merge(output, cur);

				if (leading && !handle) {
					emitter.fire(output);
					output = undefined;
				}

				doFire = () => {
					const _output = output;
					output = undefined;
					handle = undefined;
					if (!leading || numDebouncedCalls > 1) {
						emitter.fire(_output!);
					}
					numDebouncedCalls = 0;
				};

				if (typeof delay === 'number') {
					if (handle) clearTimeout(handle);
					handle = setTimeout(doFire, delay);
				} else {
					if (handle === undefined) {
						handle = null;
						queueMicrotask(doFire);
					}
				}
			});
		},
		onDidRemoveLastListener() {
			subscription.dispose();
		}
	};

	const emitter = new Emitter<O>(options);
	disposable?.add(emitter);
	return emitter.event;
}
```

#### `Event.throttle` (event.ts:366-429)
```typescript
export function throttle<I, O>(
	event: Event<I>,
	merge: (last: O | undefined, event: I) => O,
	delay: number | typeof MicrotaskDelay = 100,
	leading = true,
	trailing = true,
	leakWarningThreshold?: number,
	disposable?: DisposableStore
): Event<O> {
	// Similar to debounce but:
	// - Fires immediately on leading edge (if leading=true)
	// - Queues last value for trailing edge (if trailing=true)
	// - Prevents multiple fires within delay period
}
```

#### Other Event Operators
- `Event.once(event)` - Fires only first time
- `Event.map(event, map)` - Transform values
- `Event.filter(event, filter)` - Conditional firing
- `Event.any(...events)` - Combine multiple events
- `Event.debounce(event, merge, delay)` - Batch rapid events
- `Event.throttle(event, merge, delay)` - Rate limit
- `Event.buffer(event)` - Queue until first listener
- `Event.latch(event, equals)` - Prevent consecutive duplicates

