## 6. System Integration Patterns

### Pattern 1: CancelablePromise with CancellationToken
**How it composes:**
```typescript
// CancelablePromise USES CancellationToken internally
export function createCancelablePromise<T>(
	callback: (token: CancellationToken) => Promise<T>
): CancelablePromise<T> {
	const source = new CancellationTokenSource();

	const subscription = source.token.onCancellationRequested(() => {
		subscription.dispose();  // IDisposable
		reject(new CancellationError());
	});
	// ...
}
```

**Result:** User can `promise.cancel()` which triggers token cancellation.

### Pattern 2: Throttler with Cancellation
**How it composes:**
```typescript
export class Throttler implements IDisposable {
	private cancellationTokenSource: CancellationTokenSource;

	queue<T>(promiseFactory: ICancellableTask<Promise<T>>): Promise<T> {
		const activePromise = promiseFactory(this.cancellationTokenSource.token);
		// Factory receives cancellation token
	}

	dispose(): void {
		this.cancellationTokenSource.cancel();  // Cancels all queued work
	}
}
```

**Result:** Throttler passes its token to factories, allowing coordinated cancellation on disposal.

### Pattern 3: Event-based Async Coordination
**How it composes:**
```typescript
// Limiter uses Emitter for idle notification
export class Limiter<T> implements ILimiter<T> {
	private readonly _onDrained: Emitter<void>;

	get onDrained(): Event<void> {
		return this._onDrained.event;
	}

	whenIdle(): Promise<void> {
		return this.size > 0
			? Event.toPromise(this.onDrained)
			: Promise.resolve();
	}
}
```

**Result:** Async tasks can await `Event.toPromise(limiter.onDrained)` for completion.

### Pattern 4: DisposableStore with Event Listeners
**How it composes:**
```typescript
function debounce<I, O>(
	event: Event<I>,
	merge: (last: O | undefined, event: I) => O,
	delay: number,
	leading = false,
	flushOnListenerRemove = false,
	leakWarningThreshold?: number,
	disposable?: DisposableStore  // <-- Accepts DisposableStore
): Event<O> {
	const emitter = new Emitter<O>(options);
	disposable?.add(emitter);  // Register emitter for cleanup
	return emitter.event;
}
```

**Result:** Event emitters can be registered in a store for coordinated cleanup.

### Pattern 5: Cancellation + Disposables Together
**How it composes:**
```typescript
export function cancelOnDispose(store: DisposableStore): CancellationToken {
	const source = new CancellationTokenSource();
	store.add({ dispose() { source.cancel(); } });
	return source.token;
}
```

**Result:** When `store.dispose()` is called, the token is automatically cancelled.

### Pattern 6: AsyncEmitter with IWaitUntil
**How it composes:**
```typescript
export class AsyncEmitter<T extends IWaitUntil> extends Emitter<T> {
	async fireAsync(
		data: IWaitUntilData<T>,
		token: CancellationToken,
		promiseJoin?: (p: Promise<unknown>, listener: Function) => Promise<unknown>
	): Promise<void> {
		// Fires event and awaits listeners' promises
		// Respects cancellation token
	}
}

// Usage:
